import { Button } from "@mui/material";
import AddIcon from '@mui/icons-material/Add';

export default function ButtonFieldAdd(props){
    return(
        <div>
            <Button style={props.style} variant={props.variant} startIcon={<AddIcon />} size={props.size}
              onClick={props.onClickHandler}> 
                {props.name} 
            </Button>
        </div>
    )
}