import { Box, IconButton } from "@mui/material";
import ImageField from "../ImageField/ImageField";

const icon= require('../../Images/scope.jpg')
export default function AppointIcon(){
    return(
        <>
        <Box sx={{display:'flex',justifyContent:'flex-end'}}>
         <IconButton sx={{bottom: '60px',position: 'fixed !important',
          right: '5px',zIndex: 997,}}>
           <ImageField image={{src:icon}} style={{height:60,width:60}}/>
         </IconButton>
        </Box>
        </>
    )
}