import * as React from 'react';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Typography from '@mui/material/Typography';
import { Link } from 'react-router-dom';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import { BottomNavigation, BottomNavigationAction, IconButton } from '@mui/material';
import Box from '@mui/material/Box';
import SettingsIcon from '@mui/icons-material/Settings';


export default function BottomFooter(props){
    return(
        <>
        <Box sx={{borderTop:'1px solid #e9e9e9',bottom: '0',width:1150,right:'0',position:'fixed',
         backgroundColor:'#fbfbfb'}}>
          <BottomNavigation>
            <Box sx={{display:'flex',flexGrow:2,justifyContent:'flex-start',alignItems:'center'}}>
               <Breadcrumbs  separator={<NavigateNextIcon fontSize="small" style={{opacity:'.5'}} />} aria-label="breadcrumb">
                  {
                    props.footerLink.map((item)=>{
                       return <>
                        <Link  style={{textDecoration:'none',color: '#000',opacity:'.4',
                              fontSize:'14px',fontFamily:'Lato,sans-serif',marginLeft:20,display:'flex',
                              }}>
                           {item.page}   
                       </Link>
                       <Typography key="2" color="text.primary" style={{ fontSize:'14px',fontFamily:'Lato,sans-serif',
                        }}>
                           {item.name}
                       </Typography>
                       </>
                    })
                  }
                </Breadcrumbs>
            </Box>
            <Box sx={{display:'flex',justifyContent:'center',alignItems:'center'}}>
              <Typography style={{fontSize:"14px",fontFamily:"Lato,sans-serif"}}>Version 1.4.0</Typography>
              <IconButton>
                <SettingsIcon style={{color:'blue',}}/>
              </IconButton>
            </Box>
          </BottomNavigation>
        </Box>
        </>
    )
}