import * as React from 'react';
import { styled } from '@mui/material/styles';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell, { tableCellClasses } from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Paper from '@mui/material/Paper';
import { useState } from 'react';
import { useEffect } from 'react';

const StyledTableCell = styled(TableCell)(({ theme }) => ({
  [`&.${tableCellClasses.head}`]: {
    backgroundColor:' rgba(31,32,34,.1)',
    color: 'black',
    fontWeight:700,
  },
  [`&.${tableCellClasses.body}`]: {
    fontSize: 14,
    backgroundColor: 'hsla(0,0%,92%,.3)',
  },
}));

const StyledTableRow = styled(TableRow)(({ theme }) => ({
  '&:nth-of-type(odd)': {
    
  },

  '&:last-child td, &:last-child th': {
    border: 0,
  },
}));

function createData (
  img,
  name, 
  email,
  number, 
  date,
  fromTo,
  doctor,
  injury,
 ) {
  return { img, name, email, number, date,fromTo,doctor,injury };
}

export default function TableData() {
    const [appointment,setAppointment]=useState([]);

    useEffect(()=>{
        fetch("/json/lastAppointment.json")
        .then(res=>res.json())
        .then(res=>{
            console.log(res);
            setAppointment(res)
        })
    },[])

  return (
    <TableContainer sx={{marginTop:5}}component={Paper}>
      <Table sx={{ minWidth: 700 }} aria-label="customized table">
        <TableHead>
          <TableRow>
            <StyledTableCell>Photo</StyledTableCell>
            <StyledTableCell align="left">Name</StyledTableCell>
            <StyledTableCell align="left">Email</StyledTableCell>
            <StyledTableCell align="left">Date</StyledTableCell>
            <StyledTableCell align="left">Number</StyledTableCell>
            <StyledTableCell align="left">Visit time</StyledTableCell>
            <StyledTableCell align="left">Doctor</StyledTableCell>
            <StyledTableCell align="left">Injury/Condition</StyledTableCell>

          </TableRow>
        </TableHead>
        <TableBody>
          {appointment.map((row) => (
            <StyledTableRow key={row.name}>
              <StyledTableCell component="th" scope="row">
                <img src={row.img} style={{borderRadius:'50%'}}/>
              </StyledTableCell>
              <StyledTableCell align="left">{row.name}</StyledTableCell>
              <StyledTableCell style={{color:"blue"}} align="left">{row.email}</StyledTableCell>
              <StyledTableCell align="left">{row.date}</StyledTableCell>
              <StyledTableCell style={{color:"blue"}} align="left">{row.number}</StyledTableCell>
              <StyledTableCell align="left">{row.fromTo}</StyledTableCell>
              <StyledTableCell align="left">{row.doctor}</StyledTableCell>
              <StyledTableCell align="left">{row.injury}</StyledTableCell>
            </StyledTableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
}