import { SET_PASSWORD, SET_USER_NAME,SET_EMAIL_ADDRESS,SET_NAME,SET_PASSWORD1 } from "../Constants/Constants";
import { InitialState } from "../Store/InitialState";

export default function SignInReducer(state=InitialState,action){
    switch (action.type) {
        case SET_USER_NAME:
            return{
                ...state,
                user:{
                    username:action.payload
                }
            }
            
        case SET_PASSWORD:
            return{
                ...state,
                user:{
                    password:action.payload
                }
            }
        case SET_NAME:
                return{
                    ...state,
                    user1:{
                        name:action.payload
                }
         }
        case SET_EMAIL_ADDRESS:
            return{
                 ...state,
                 user1:{
                      email:action.payload
                    }
             }
        case SET_PASSWORD1:
            return{
                 ...state,
                user1:{
                     password:action.payload
            }
        }
        
        default:
            return{
                ...state
            }
    }
}