import {  SET_EMAIL_ADDRESS, SET_NAME,  SET_PASSWORD, SET_PASSWORD1, SET_USER_NAME, } from "../Constants/Constants"

export function setUsername(payload){
    return{
        type:SET_USER_NAME,
        payload
    }
}
export function setPassword(payload){
    return{
        type:SET_PASSWORD,
        payload
    }
}
export function setName(payload){
    return{
        type:SET_NAME,
        payload
    }
}

export function setEmailAddess(payload){
    return{
        type:SET_EMAIL_ADDRESS,
        payload
    }
}
export function setPassword1(payload){
    return{
        type:SET_PASSWORD1,
        payload
    }
}
